  `DOCUMENT_STATUS` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'DRAFT' COMMENT 'Status: DRAFT, FINAL, AMENDED, ADDENDED',
  `AUTHENTICATED` tinyint(1) DEFAULT '0' COMMENT 'Document authenticated',
