  `ADDENDUM_REASON` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT 'Addendum reason',
  `REVIEW_STATUS` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'PENDING' COMMENT 'Review status',
  `REVIEWED_BY` int DEFAULT NULL COMMENT 'Reviewed by',
  `REVIEW_DATE` datetime DEFAULT NULL COMMENT 'Review date',
  `APPROVAL_STATUS` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'PENDING' COMMENT 'Approval status',
  `APPROVED_BY` int DEFAULT NULL COMMENT 'Approved by',
  `APPROVAL_DATE` datetime DEFAULT NULL COMMENT 'Approval date',
  `LEGAL_STATUS` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Legal status',
  `RETENTION_PERIOD` int DEFAULT NULL COMMENT 'Retention period in years',
  `ARCHIVE_STATUS` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'ACTIVE' COMMENT 'Archive status',
  `ARCHIVE_DATE` datetime DEFAULT NULL COMMENT 'Archive date',
  `DELETION_DATE` datetime DEFAULT NULL COMMENT 'Scheduled deletion date',
